SELECT * FROM consumer;

-- Total revenue generated by male vs female customers
SELECT gender, SUM(purchase_amount) AS revenue
FROM consumer
GROUP BY gender;

-- Customers who used discount but still spent more than average purchase amount
SELECT customer_id, purchase_amount
FROM consumer
WHERE discount_applied = 'Yes' AND purchase_amount >=(SELECT AVG(purchase_amount) FROM consumer);

-- top 5 products with the highest average review rating
SELECT item_purchased, ROUND(AVG(review_rating),2) AS "Average Product Rating"
FROM consumer
GROUP BY item_purchased
order by AVG(review_rating) DESC
LIMIT 5;


-- compare the average purchase amounts between standard and express shipping
SELECT shipping_type, 
ROUND(AVG(purchase_amount), 2)
FROM consumer
WHERE shipping_type IN ('Standard','Express')
GROUP BY shipping_type;


-- compare average spend and total revenue between subscrivers and non-subscribers
SELECT subscription_status,
COUNT(customer_id) AS total_customers,
ROUND(AVG(purchase_amount), 2) AS avg_spend,
ROUND(SUM(purchase_amount), 2) AS total_revenue
FROM consumer
GROUP BY subscription_status
ORDER BY total_revenue, avg_spend DESC;

-- 5 products which have the highest percentage of purchase with discounts applied.
SELECT item_purchased,
ROUND(SUM(CASE WHEN discount_applied = 'Yes'THEN 1 ELSE 0 END)/COUNT(*) * 100, 2) AS discount_rate
FROM consumer
GROUP BY item_purchased
ORDER BY discount_rate DESC
LIMIT 5;


-- segement customers into New, Returning, and Loyal based on their total number of previous
-- purchases, and show the count of each segment.alter
WITH customer_type AS (
SELECT customer_id, previous_purchases,
CASE 
	WHEN previous_purchases = 1 THEN 'NEW'
    WHEN previous_purchases BETWEEN 2 and 10 THEN 'Returning'
    ELSE 'Loyal'
    END AS customer_segment
FROM consumer
)
SELECT customer_segment, COUNT(*) AS "Number of Customers"
FROM customer_type
GROUP BY customer_segment;


-- top 3 most purchased products within each category
WITH  item_counts AS (
SELECT category,
item_purchased,
COUNT(customer_id) AS total_orders,
ROW_NUMBER() OVER(PARTITION BY category ORDER BY COUNT(customer_id) DESC) AS item_rank
FROM consumer
GROUP BY category, item_purchased
) 
SELECT item_rank, category, item_purchased, total_orders
FROM item_counts
WHERE item_rank <=3;


-- check if customers who are repeat buyers (more than 5 pervious pruchases ) are also likely to subscribe
SELECT subscription_status,
COUNT(customer_id) AS repeat_buyers
FROM consumer
WHERE previous_purchases > 5
GROUP BY subscription_status;


-- revenue contribution of each age group
SELECT age_group,
SUM(purchase_amount) AS total_revenue
FROM consumer
GROUP BY age_group
ORDER BY total_revenue DESC;